import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const AdminDashboard = () => {
  const { user, token } = useAuth();
  const navigate = useNavigate();
  const [salesData, setSalesData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (user?.role !== 'admin') {
      navigate('/');
      return;
    }
    fetchSalesData();
  }, [user, navigate, token]);

  const fetchSalesData = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/admin/sales-report', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setSalesData(response.data);
    } catch (error) {
      console.error('Failed to fetch sales data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!user || user.role !== 'admin') {
    return <div>Access denied. Admin only.</div>;
  }

  if (loading) {
    return <div>Loading dashboard...</div>;
  }

  return (
    <div className="admin-dashboard">
      <h1>Admin Dashboard</h1>
      
      <div className="sales-summary">
        <div className="summary-card">
          <h3>Total Sales</h3>
          <p className="summary-value">₹{salesData?.totalSales || 0}</p>
        </div>
        <div className="summary-card">
          <h3>Total Orders</h3>
          <p className="summary-value">{salesData?.totalOrders || 0}</p>
        </div>
      </div>

      <div className="sales-report">
        <h2>Sales Report</h2>
        <table className="sales-table">
          <thead>
            <tr>
              <th>Product Name</th>
              <th>Quantity Sold</th>
              <th>Amount</th>
            </tr>
          </thead>
          <tbody>
            {salesData?.productSales?.map((product, index) => (
              <tr key={index}>
                <td>{product.name}</td>
                <td>{product.quantity}</td>
                <td>₹{Math.round(product.amount * 83)}</td>
              </tr>
            )) || <tr><td colSpan="3">No sales data</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminDashboard;
